const $ = (s, root=document) => root.querySelector(s);
const $$ = (s, root=document) => Array.from(root.querySelectorAll(s));
let state = { locale: localStorage.getItem('wc2026Locale') || 'ko', selectedTeam: localStorage.getItem('wc2026Team') || 'KOR', matches: structuredClone(DATA.matches) };
function teamName(code){ const t=DATA.teams[code]; return t ? `${t.flag} ${state.locale==='ko'?t.nameKo:t.nameEn}` : code; }
function teamPlain(code){ const t=DATA.teams[code]; return t ? (state.locale==='ko'?t.nameKo:t.nameEn) : code; }
function matchKey(a,b){ return [a,b].sort().join('_'); }
function resultOf(m){ if(m.homeGoals==null||m.awayGoals==null||m.homeGoals===''||m.awayGoals==='') return null; return [Number(m.homeGoals), Number(m.awayGoals)]; }
function calcTable(group){
  const teams=DATA.groups[group].map(code=>({code,group,p:0,w:0,d:0,l:0,gf:0,ga:0,gd:0,pts:0,tieNote:''})); const map=Object.fromEntries(teams.map(t=>[t.code,t]));
  state.matches.filter(m=>m.group===group).forEach(m=>{ const r=resultOf(m); if(!r) return; const [hg,ag]=r; let h=map[m.home], a=map[m.away]; h.p++; a.p++; h.gf+=hg; h.ga+=ag; a.gf+=ag; a.ga+=hg; if(hg>ag){h.w++;a.l++;h.pts+=3}else if(hg<ag){a.w++;h.l++;a.pts+=3}else{h.d++;a.d++;h.pts++;a.pts++} });
  teams.forEach(t=>t.gd=t.gf-t.ga);
  return sortWithTies(teams, group);
}
function miniStats(codes, group){
  const mini=Object.fromEntries(codes.map(c=>[c,{code:c,pts:0,gf:0,ga:0,gd:0}]));
  state.matches.filter(m=>m.group===group && codes.includes(m.home) && codes.includes(m.away)).forEach(m=>{ const r=resultOf(m); if(!r)return; const [hg,ag]=r; let h=mini[m.home],a=mini[m.away]; h.gf+=hg;h.ga+=ag;a.gf+=ag;a.ga+=hg; if(hg>ag)h.pts+=3; else if(hg<ag)a.pts+=3; else {h.pts++;a.pts++;} });
  Object.values(mini).forEach(t=>t.gd=t.gf-t.ga); return mini;
}
function sortWithTies(teams, group){
  teams.sort((a,b)=> b.pts-a.pts || b.gd-a.gd || b.gf-a.gf || a.code.localeCompare(b.code));
  let out=[]; for(let i=0;i<teams.length;){ let j=i+1; while(j<teams.length && teams[j].pts===teams[i].pts && teams[j].gd===teams[i].gd && teams[j].gf===teams[i].gf) j++; let chunk=teams.slice(i,j); if(chunk.length>1){ const mini=miniStats(chunk.map(t=>t.code), group); chunk.sort((a,b)=> mini[b.code].pts-mini[a.code].pts || mini[b.code].gd-mini[a.code].gd || mini[b.code].gf-mini[a.code].gf || a.code.localeCompare(b.code)); chunk.forEach(t=>{t.tieNote='상대전적/미니리그 적용 또는 페어플레이 필요 가능';}); } out.push(...chunk); i=j; }
  return out;
}
function allTables(){ const o={}; Object.keys(DATA.groups).forEach(g=>o[g]=calcTable(g)); return o; }
function rankThirds(tables){ return Object.keys(tables).map(g=>({...tables[g][2], thirdGroup:g})).sort((a,b)=> b.pts-a.pts || b.gd-a.gd || b.gf-a.gf || a.code.localeCompare(b.code)); }
function slotTeam(slot,tables,thirds){ if(/^([123])([A-L])$/.test(slot)){ const [,pos,g]=slot.match(/^([123])([A-L])$/); return tables[g][Number(pos)-1]?.code || slot; } return null; }
function thirdAssignment(thirds){ const adv=thirds.slice(0,8).map(t=>t.thirdGroup).sort().join(''); return DATA.thirdPlaceMap[adv] || null; }
function r32Slots(tables,thirds){ const assign=thirdAssignment(thirds); const by3=Object.fromEntries(thirds.slice(0,8).map(t=>['3'+t.thirdGroup,t.code])); return DATA.bracket.map(([id,a,b])=>{ let bb=b; if(b==='3X'){ const winner = ({74:'1E',77:'1I',79:'1A',80:'1L',81:'1D',82:'1G',85:'1B',87:'1K'})[id]; bb=assign?.assign?.[winner] || '3?'; } return {id,a,b:bb,ta:slotTeam(a,tables,thirds),tb:bb.startsWith('3')?by3[bb]:slotTeam(bb,tables,thirds),rawB:bb}; }); }
function statusFor(group,pos,thirds){ if(pos<2) return '<span class="wc-badge in">32강</span>'; if(pos===2){ const rank=thirds.findIndex(t=>t.thirdGroup===group)+1; return rank<=8?`<span class="wc-badge in">3위 ${rank}위 진출권</span>`:`<span class="wc-badge out">3위 ${rank}위 탈락권</span>`;} return '<span class="wc-badge out">탈락권</span>'; }
function completedMatches(){ return state.matches.filter(m=>resultOf(m)).sort((a,b)=>a.group.localeCompare(b.group)); }
function renderDashboard(tables,thirds){ const done=completedMatches(); const goals=done.reduce((s,m)=>{const [h,a]=resultOf(m); return s+h+a;},0); const qualified=Object.keys(tables).length*2 + thirds.slice(0,8).length; $('#wc-hero-kpis').innerHTML=`<div class="wc-kpi"><b>${done.length}</b><span>입력 경기</span></div><div class="wc-kpi"><b>${goals}</b><span>총 득점</span></div><div class="wc-kpi"><b>${qualified}</b><span>현재 진출권</span></div><div class="wc-kpi"><b>${thirds[7]?.pts ?? 0}pts</b><span>3위 8위 커트</span></div>`; $('#wc-scoreboard').innerHTML=done.slice(-8).reverse().map(m=>{const [h,a]=resultOf(m); return `<div class="wc-score-line"><span class="wc-score-team">${teamName(m.home)}</span><strong class="wc-score">${h} : ${a}</strong><span class="wc-score-team">${teamName(m.away)}</span></div>`;}).join('') || '<p class="wc-note">아직 입력된 경기가 없다.</p>'; const eighth=thirds[7], ninth=thirds[8]; $('#wc-cutline').innerHTML=[eighth,ninth].filter(Boolean).map((t,i)=>`<div class="wc-mini-row"><span>${i===0?'8위 진출선':'9위 탈락선'}</span><b>${teamName(t.code)} · ${t.pts}점 · ${t.gd>0?'+':''}${t.gd}</b></div>`).join('')+`<div class="wc-progress"><span style="width:${Math.min(100,Math.max(8,((eighth?.pts||0)/9)*100))}%"></span></div>`; }
function renderControls(){ $('#locale-ko').classList.toggle('active',state.locale==='ko'); $('#locale-en').classList.toggle('active',state.locale==='en'); const sel=$('#team-select'); sel.innerHTML=Object.keys(DATA.teams).map(c=>`<option value="${c}" ${c===state.selectedTeam?'selected':''}>${teamName(c)}</option>`).join(''); }
function renderMatches(){ const wrap=$('#wc-match-inputs'); wrap.innerHTML=Object.keys(DATA.groups).map(g=>`<details class="wc-group-editor"><summary>Group ${g} 경기 입력</summary>${state.matches.filter(m=>m.group===g).map(m=>`<div class="wc-score-row"><span>${teamName(m.home)}</span><input type="number" min="0" data-mid="${m.id}" data-side="home" value="${m.homeGoals??''}"><b>:</b><input type="number" min="0" data-mid="${m.id}" data-side="away" value="${m.awayGoals??''}"><span>${teamName(m.away)}</span></div>`).join('')}</details>`).join('');
  $$('input[data-mid]',wrap).forEach(inp=>inp.addEventListener('input',e=>{ const m=state.matches.find(x=>x.id===e.target.dataset.mid); const val=e.target.value===''?null:Number(e.target.value); if(e.target.dataset.side==='home')m.homeGoals=val; else m.awayGoals=val; renderAll(false); })); }
function renderStandings(tables,thirds){ $('#wc-groups').innerHTML=Object.keys(tables).map(g=>`<section class="wc-card"><h3>Group ${g}</h3><table><thead><tr><th>#</th><th>팀</th><th>경기</th><th>승</th><th>무</th><th>패</th><th>승점</th><th>득실</th><th>상태</th></tr></thead><tbody>${tables[g].map((t,i)=>`<tr class="${t.code===state.selectedTeam?'sel':''}"><td>${i+1}</td><td>${teamName(t.code)}${t.tieNote?'<small title="'+t.tieNote+'"> · H2H</small>':''}</td><td>${t.p}</td><td>${t.w}</td><td>${t.d}</td><td>${t.l}</td><td><b>${t.pts}</b></td><td>${t.gd>0?'+':''}${t.gd}</td><td>${statusFor(g,i,thirds)}</td></tr>`).join('')}</tbody></table></section>`).join('');
  $('#wc-thirds').innerHTML=`<table><thead><tr><th>순위</th><th>조</th><th>팀</th><th>승점</th><th>득실</th><th>득점</th><th>상태</th></tr></thead><tbody>${thirds.map((t,i)=>`<tr class="${i<8?'q':'nq'} ${t.code===state.selectedTeam?'sel':''}"><td>${i+1}</td><td>${t.thirdGroup}</td><td>${teamName(t.code)}</td><td>${t.pts}</td><td>${t.gd>0?'+':''}${t.gd}</td><td>${t.gf}</td><td>${i<8?'32강':'탈락권'}</td></tr>`).join('')}</tbody></table>`; }
function renderBracket(tables,thirds){ const slots=r32Slots(tables,thirds); const slotMap=Object.fromEntries(slots.map(s=>[s.id,s])); $('#wc-r32').innerHTML=slots.map(s=>`<div class="wc-bracket-match ${(s.ta===state.selectedTeam||s.tb===state.selectedTeam)?'sel':''}" data-a="${s.ta||''}" data-b="${s.tb||''}"><b>M${s.id}</b><span>${s.ta?teamName(s.ta):s.a}</span><em>vs</em><span>${s.tb?teamName(s.tb):s.rawB}</span><small>${s.a} vs ${s.rawB}</small></div>`).join('');
  $('#wc-r16').innerHTML=DATA.r16.map(([id,a,b])=>`<div class="wc-bracket-match"><b>M${id}</b><span>Winner M${a}</span><em>vs</em><span>Winner M${b}</span></div>`).join('');
  $$('.wc-bracket-match[data-a]').forEach(el=>el.addEventListener('click',()=>renderH2H(el.dataset.a,el.dataset.b)));
}
function renderH2H(a=state.selectedTeam,b=null){ let html=''; if(!b){ html='<p>대진표의 32강 매치를 클릭하면 상대전적 메모를 보여준다.</p>'; } else { const rec=DATA.h2h[matchKey(a,b)]; html=`<h3>${teamName(a)} vs ${teamName(b)}</h3>`+(rec?`<p>${state.locale==='ko'?rec.summaryKo:rec.summaryEn}</p>`:'<p>저장된 역사적 상대전적 메모가 아직 없다. 조별 동률 계산은 입력된 경기 결과 기준 상대전적으로 별도 처리된다.</p>'); } $('#wc-h2h').innerHTML=html; }
function renderTeamPath(tables,thirds){ const code=state.selectedTeam; const slots=r32Slots(tables,thirds).filter(s=>s.ta===code||s.tb===code); const tablePos=Object.entries(tables).flatMap(([g,arr])=>arr.map((t,i)=>({g,pos:i+1,code:t.code,stat:t}))).find(x=>x.code===code); const stat=tablePos?.stat; const pct=stat?Math.min(100,(stat.pts/9)*100):0; $('#wc-team-path').innerHTML=`<h3>${teamName(code)}</h3><div class="wc-mini-list"><div class="wc-mini-row"><span>현재 순위</span><b>Group ${tablePos?.g || '?'} · ${tablePos?.pos || '?'}위</b></div>${stat?`<div class="wc-mini-row"><span>전적</span><b>${stat.w}승 ${stat.d}무 ${stat.l}패 · ${stat.pts}점</b></div><div class="wc-progress"><span style="width:${pct}%"></span></div>`:''}</div>`+(slots[0]?`<p>예상 32강: <b>M${slots[0].id}</b><br>${teamName(slots[0].ta)} vs ${teamName(slots[0].tb)}</p>`:'<p>현재 입력값 기준 32강 진출권 밖이거나 대진 미확정.</p>'); }
function renderSources(){ $('#wc-sources').innerHTML=DATA.sources.map(s=>`<li>${s}</li>`).join(''); }
function renderAll(renderInputs=true){ renderControls(); const tables=allTables(); const thirds=rankThirds(tables); renderDashboard(tables,thirds); if(renderInputs) renderMatches(); renderStandings(tables,thirds); renderBracket(tables,thirds); renderTeamPath(tables,thirds); renderH2H(); renderSources(); }
document.addEventListener('DOMContentLoaded',()=>{ $('#locale-ko').onclick=()=>{state.locale='ko';localStorage.setItem('wc2026Locale','ko');renderAll();}; $('#locale-en').onclick=()=>{state.locale='en';localStorage.setItem('wc2026Locale','en');renderAll();}; $('#team-select').onchange=e=>{state.selectedTeam=e.target.value;localStorage.setItem('wc2026Team',state.selectedTeam);renderAll(false);}; $('#reset-scores').onclick=()=>{state.matches=structuredClone(DATA.matches);renderAll();}; renderAll(); });
